DROP TABLE IF EXISTS `activity_signup`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `activity_signup` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `activity_id` bigint NOT NULL COMMENT '活动ID（关联club_activity.id）',
  `student_id` bigint NOT NULL COMMENT '学生ID（关联sys_user.id）',
  `status` tinyint DEFAULT '0' COMMENT '审核状态：0-待审核, 1-已通过, 2-已驳回',
  `signup_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '报名时间',
  `checkin_status` tinyint DEFAULT '0' COMMENT '签到状态：0-未签到，1-已签到',
  `checkin_time` datetime DEFAULT NULL COMMENT '签到时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_activity_student` (`activity_id`,`student_id`) COMMENT '一人一活动只能报名一次',
  KEY `idx_student_id` (`student_id`) COMMENT '学生ID索引',
  KEY `idx_checkin_status` (`checkin_status`) COMMENT '签到状态索引',
  KEY `idx_stu_act` (`student_id`,`activity_id`),
  CONSTRAINT `fk_signup_activity` FOREIGN KEY (`activity_id`) REFERENCES `club_activity` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_signup_student` FOREIGN KEY (`student_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='活动报名记录表';
