DROP TABLE IF EXISTS `club_activity`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `club_activity` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `club_id` bigint NOT NULL COMMENT '所属社团ID（关联club_info.id）',
  `activity_name` varchar(100) NOT NULL COMMENT '活动名称',
  `cover` varchar(500) NOT NULL COMMENT '活动封面',
  `start_time` datetime NOT NULL COMMENT '活动开始时间',
  `end_time` datetime NOT NULL COMMENT '活动结束时间',
  `location` varchar(100) NOT NULL COMMENT '活动地点',
  `content` text COMMENT '活动详情介绍',
  `max_people` int DEFAULT '0' COMMENT '最大参与人数（0为不限）',
  `status` tinyint DEFAULT '0' COMMENT '审批状态：0-待审核，1-已通过，2-已驳回',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_club_id` (`club_id`) COMMENT '社团ID索引',
  KEY `idx_start_time` (`start_time`) COMMENT '活动开始时间索引',
  KEY `idx_status` (`status`) COMMENT '审批状态索引',
  KEY `idx_act_club` (`id`,`club_id`),
  CONSTRAINT `fk_activity_club` FOREIGN KEY (`club_id`) REFERENCES `club_info` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='社团活动表';
/*!40101 SET character_set_client = @saved_cs_client */;

