INSERT INTO `club_activity` VALUES (1,3,'新国辩 · 全国大学生新生辩论赛','/uploads/cover/FreshmanDebate.png','2025-11-22 14:00:00','2025-11-22 17:00:00','学十九楼205室、学十九楼207室','本次辩论赛旨在提升大学生逻辑思辨、语言表达与临场反应能力，围绕社会热点、校园议题、价值观念等展开激烈辩论。赛事分为初赛、复赛、决赛三个阶段，邀请专业评委进行点评打分，为热爱辩论的新生提供展示自我、交流思想的优质平台。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(2,1,'春季运动会','/uploads/cover/SpringSport.png','2026-04-16 00:00:00','2026-04-17 23:59:59','操场','春季运动会是校园年度大型体育盛会，包含短跑、长跑、跳远、跳高、接力赛、拔河、团体操等多个项目。面向全校师生开放报名，倡导“健康第一、团结协作、奋勇拼搏”的体育精神，丰富校园文化生活，增强师生身体素质与集体凝聚力。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(3,4,'雷锋月外展活动','/uploads/cover/LeiFengMonth.jpg','2026-03-22 00:00:00','2026-03-22 23:59:59','夏日广场','为传承和弘扬雷锋精神，开展志愿服务、文明宣传、爱心帮扶、公益互动等外展活动。现场设置公益展示区、便民服务区、互动体验区，号召同学们学习雷锋事迹、践行雷锋精神，用实际行动传递温暖与正能量，共建文明和谐校园。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(4,5,'春节主题作品征集','/uploads/cover/WorksCollection.png','2026-02-01 00:00:00','2026-03-01 23:59:59','线上','面向全校征集春节主题原创作品，形式包含手工作品、绘画、书法、摄影、剪纸、文创设计等。作品需紧扣春节文化、年味氛围、团圆祝福等主题，优秀作品将进行线上展示与表彰，传承中华优秀传统文化，展现同学们的创意与才华。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(5,4,'北京半程马拉松志愿者招募','/uploads/cover/VolunteersWanted.png','2026-03-20 00:00:00','2026-04-12 23:59:59','线上','为北京半程马拉松赛事招募志愿者，主要负责赛事引导、物资发放、补给站服务、秩序维护、选手协助等工作。组委会提供统一服装、志愿服务证明、培训与保障，欢迎有责任心、有爱心、能按时参与的同学报名，助力赛事顺利举办，收获志愿经历与成长。',116,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(6,6,'校园十佳歌手大赛','/uploads/cover/TopTenSingers.jpg','2025-10-19 18:00:00','2026-10-19 22:00:00','东操场','校园十佳歌手大赛是最具影响力的校园文艺赛事，为热爱音乐、擅长演唱的同学提供展示舞台。选手通过海选、复赛、决赛层层比拼，演唱风格不限，由专业评委与观众投票共同评选出校园十佳歌手，打造视听盛宴，绽放青春风采。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(7,6,'星夜荧光跑×“壹仟个现场”草坪音乐会','/uploads/cover/StarryNightRunAndLawnConcert.png','2025-10-03 18:00:00','2025-10-26 21:00:00','西操场','荧光跑结合草坪音乐会，打造沉浸式青春夜晚。参与者佩戴荧光装备环绕校园夜跑，感受运动与光影的魅力；结束后在草坪开展音乐会，现场演唱、乐队表演、互动游戏，营造轻松热烈的氛围，丰富课余生活，留下难忘的校园青春记忆。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(8,8,'第二十五届足协杯','/uploads/cover/SchoolFACup.png','2025-11-03 00:00:00','2025-11-06 23:59:59','东足球场、西足球场','足协杯是校园足球顶级赛事，汇聚各学院、各足球爱好者队伍同台竞技。赛事采用正规足球赛制，注重公平竞技与团队配合，为足球爱好者提供交流切磋、展示球技的平台，传播足球文化，激发校园运动热情，展现青春活力与体育精神。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:03'),(9,7,'“引航杯”新生篮球赛','/uploads/cover/NoviceBasketballGame.png','2025-09-25 00:00:00','2025-09-29 23:59:59','篮球场','专为新生打造的篮球赛事，以班级或学院为单位组队参赛，包含5V5正式比赛、技巧挑战等环节。旨在帮助新生快速融入校园、结交好友、增强团队意识，展现新生朝气蓬勃、勇于拼搏的精神面貌，推动校园篮球文化发展。',NULL,1,'2026-04-07 20:15:05','2026-04-09 21:11:25'),(10,2,'ACM 校内模拟赛','/uploads/cover/ACM.png','2026-05-01 09:00:00','2026-05-01 14:00:00','机房 302','算法能力大比拼，为省赛选拔优秀选手。',50,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(11,28,'新生杯羽毛球赛','/uploads/cover/BadmintonGame.png','2026-05-05 14:00:00','2026-05-06 18:00:00','体育馆','羽毛球单打、双打赛，展示青春活力。',100,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(12,24,'48小时黑客马拉松','/uploads/cover/Hackathon.png','2026-05-15 18:00:00','2026-05-17 18:00:00','图书馆报告厅','封闭式软件开发挑战，极客们的狂欢。',60,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(13,25,'校园春日摄影展','/uploads/cover/PhotoEx.png','2026-04-20 08:00:00','2026-04-30 22:00:00','文化长廊','征集并展示春季校园美照，定格瞬间。',NULL,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(14,26,'草地吉他民谣夜','/uploads/cover/GuitarNight.png','2026-05-20 19:00:00','2026-05-20 21:00:00','南草坪','围坐草坪，弹唱经典民谣，共度浪漫夜晚。',200,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(15,35,'校园棋王争霸赛','/uploads/cover/Chess.png','2026-05-12 13:00:00','2026-05-12 17:00:00','学生活动中心','围棋、五子棋、象棋多项博弈对抗。',40,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(16,30,'考前心理减压讲座','/uploads/cover/PsychologyTalk.png','2026-06-10 14:00:00','2026-06-10 16:00:00','多功能厅','特邀心理专家讲解如何应对考试焦虑。',150,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(17,31,'RoboMaster 战队选拔','/uploads/cover/RobotMatch.png','2026-05-18 09:00:00','2026-05-18 18:00:00','工程实训中心','选拔有志于机器人竞技的软硬件开发人才。',30,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(18,32,'英语口语嘉年华','/uploads/cover/EnglishFest.png','2026-05-25 15:00:00','2026-05-25 18:00:00','夏日广场','外教互动，趣味英语闯关游戏。',120,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(19,33,'舞动青春快闪','/uploads/cover/DanceShow.png','2026-06-01 12:00:00','2026-06-01 13:00:00','食堂门口','由舞蹈社带来的激情街舞快闪活动。',NULL,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(20,34,'轮滑刷街日','/uploads/cover/SkatingDay.png','2026-05-04 16:00:00','2026-05-04 18:00:00','中心校道','全校轮滑爱好者共同穿越校园。',50,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(21,36,'星空观测之夜','/uploads/cover/Stars.png','2026-05-22 20:00:00','2026-05-22 23:00:00','教学楼顶','专业天文望远镜带你观测夏季星空。',40,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(22,37,'汉服社端午游园','/uploads/cover/HanfuEvent.png','2026-06-18 09:00:00','2026-06-18 17:00:00','文化长廊','投壶、射箭，体验传统民俗魅力。',100,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(23,38,'剧本杀逻辑挑战赛','/uploads/cover/BoardGameMatch.png','2026-05-30 14:00:00','2026-05-30 20:00:00','桌游工作室','沉浸式剧本体验，脑力与演技的对决。',24,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(24,39,'简历诊断工作坊','/uploads/cover/CareerHelp.png','2026-04-25 14:00:00','2026-04-25 17:00:00','学生活动中心','邀请名企 HR 现场一对一优化个人简历。',50,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(25,40,'高达拼装交流展','/uploads/cover/Gundam.png','2026-05-10 10:00:00','2026-05-10 18:00:00','图书馆二楼','硬核模型展示与拼装技巧分享。',NULL,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(26,41,'“排球之火”联赛','/uploads/cover/VolleyballMatch.png','2026-05-21 16:00:00','2026-05-28 18:00:00','排球场','热血排球组队赛，争夺校园最高荣誉。',12,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(27,42,'武术社防身术教学','/uploads/cover/Kungfu.png','2026-05-08 19:00:00','2026-05-08 21:00:00','校武术馆','实战防身技巧免费公开课，欢迎参与。',80,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(28,43,'急救知识实操培训','/uploads/cover/FirstAid.png','2026-05-11 14:00:00','2026-05-11 17:00:00','红十字教室','心肺复苏及包扎技巧考核与教学。',60,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(29,44,'滑板障碍挑战赛','/uploads/cover/SkateboardMatch.png','2026-05-16 15:00:00','2026-05-16 18:00:00','极限运动区','挑战高难度动作，滑板少年齐聚。',30,1,'2026-04-18 11:00:00','2026-04-18 11:00:00'),(30,45,'金话筒主持人大赛','/uploads/cover/MicMatch.png','2026-06-05 19:00:00','2026-06-05 22:00:00','礼堂','选拔校园优秀主持人，展现语言艺术。',20,1,'2026-04-18 11:00:00','