--
-- Table structure for table `club_info`
--

DROP TABLE IF EXISTS `club_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `club_info` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `club_name` varchar(50) NOT NULL COMMENT '社团名称',
  `leader_id` bigint NOT NULL COMMENT '社团负责人ID（关联sys_user.id）',
  `intro` text COMMENT '社团简介',
  `category` enum('功能性组织','学术类社团','公益类社团','逸趣类社团','艺术类组织&社团','体育类社团') NOT NULL DEFAULT '学术类社团' COMMENT '社团类型',
  `status` tinyint DEFAULT '0' COMMENT '审核状态：0-待审核，1-已通过，2-已驳回，3-已注销',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `tags` varchar(255) DEFAULT NULL,
  `logo` varchar(255) DEFAULT NULL COMMENT '社团logo',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_club_name` (`club_name`) COMMENT '社团名称唯一索引',
  KEY `idx_leader_id` (`leader_id`) COMMENT '负责人ID索引',
  KEY `idx_status` (`status`) COMMENT '审核状态索引',
  CONSTRAINT `fk_club_leader` FOREIGN KEY (`leader_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=53 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='社团信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `club_info`
--

LOCK TABLES `club_info` WRITE;
/*!40000 ALTER TABLE `club_info` DISABLE KEYS */;
INSERT INTO `club_info` VALUES (1,'学生会',2,'学生会是服务全校师生的核心学生组织，负责校园活动统筹、学生权益维护、校风建设等工作。我们秉持责任与奉献精神，搭建师生沟通桥梁，组织各类校园文化活动，助力校园和谐发展，培养综合管理与实践能力。','功能性组织',1,'2026-03-29 17:36:52','2026-04-16 20:06:17','学术,管理,服务','/uploads/club/StudentUnion.png'),(2,'计算机协会',2,'计算机协会专注于计算机技术学习与交流，涵盖编程开发、网络安全、软件应用、人工智能等领域。定期开展技术讲座、编程竞赛、项目实战等活动，为计算机爱好者提供学习、交流、实践平台，提升专业技能。','学术类社团',1,'2026-03-29 17:36:52','2026-04-16 20:06:17','科技,编程,计算机,学术','/uploads/club/ComputerAssociation.png'),(3,'辩论社',2,'辩论社以提升逻辑思维、语言表达与思辨能力为宗旨，围绕热点话题开展辩论训练、模拟赛事、思辨分享等活动。培养社员快速反应、清晰表达、理性思考能力，营造敢于发声、善于思考的社团氛围。','学术类社团',1,'2026-03-29 17:36:52','2026-04-16 20:06:17','学术,语言,发声,思辨','/uploads/club/DebateClub.png'),(4,'爱心公益社',2,'爱心公益社以奉献、友爱、互助为理念，组织志愿服务、公益募捐、社区帮扶、环保宣传等活动。致力于传递温暖与正能量，为有需要的群体提供帮助，培养社员社会责任感与奉献精神。','公益类社团',1,'2026-03-29 17:36:52','2026-04-16 20:06:17','志愿服务,公益,爱心','/uploads/club/LoveAndPublicWelfareClub.png'),(5,'手工DIY社',2,'手工DIY社专注于手工制作与创意创作，涵盖编织、黏土、纸艺、布艺、文创制作等内容。定期开展手工教学、作品展览、创意市集活动，为手工爱好者提供交流展示、放松身心的平台。','逸趣类社团',1,'2026-03-29 17:36:52','2026-04-16 20:06:17','艺术,手工,文艺','/uploads/club/HandmadeDIYClub.png'),(6,'音乐社',2,'音乐社汇聚热爱音乐的同学，涵盖声乐、器乐、合唱、原创音乐等方向。开展声乐教学、乐器交流、文艺演出、校园音乐会等活动，丰富校园文化生活，展现音乐魅力与青春风采。','艺术类组织&社团',1,'2026-03-29 17:36:52','2026-04-16 20:06:18','艺术,音乐,文艺,表演','/uploads/club/MusicClub.png'),(7,'篮球社',2,'篮球社以推广篮球运动、增强体质为目标，开展日常训练、技巧教学、校内联赛、校际交流赛等活动。培养社员团队协作、拼搏进取精神，享受运动乐趣，打造充满活力的体育社团。','体育类社团',1,'2026-03-29 17:36:52','2026-04-16 20:06:18','运动,体育,篮球','/uploads/club/BasketballClub.png'),(8,'足球社',2,'足球社致力于校园足球文化推广，提供专业足球训练、战术交流、赛事组织等服务。通过日常练习与比赛提升社员球技，培养团队精神与竞技意识，展现青春活力与体育精神。','体育类社团',1,'2026-03-29 17:36:52','2026-04-16 20:06:18','运动,体育,足球','/uploads/club/FootballClub.png'),(24,'极客编程社',15,'全校最硬核的编程社团。','学术类社团',1,'2026-04-15 21:53:29','2026-04-18 10:28:55','编程,算法,科技','/uploads/logo/Geek.png'),(25,'光影摄影协会',15,'发现校园之美，定格永恒瞬间。','艺术类组织&社团',1,'2026-04-15 21:53:29','2026-04-18 10:28:55','摄影,艺术,文艺','/uploads/logo/Photo.png'),(26,'民谣吉他社',15,'用琴弦拨动心弦。','艺术类组织&社团',1,'2026-04-15 21:53:29','2026-04-18 10:28:55','音乐,吉他,文艺,艺术','/uploads/logo/FolkMusic.png'),(27,'浮石文学社',15,'妙笔生花，山浮水面水浮山','学术类社团',1,'2026-04-18 10:25:34','2026-04-18 10:45:37','文学,创作,艺术','/uploads/2026/04/18/1ef324da91d74109a418674af62defdd.jpg'),(28,'羽毛球社',2,'提供羽毛球技术交流与比赛平台。','体育类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','运动,体育,羽毛球','/uploads/club/Badminton.png'),(29,'动漫社',15,'二次元文化爱好者的家园。','逸趣类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','艺术,文艺,动漫','/uploads/club/Anime.png'),(30,'心理协会',2,'关注大学生心理健康，传播心理学知识。','学术类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','健康,学术,心理','/uploads/club/Psychology.png'),(31,'机器人校队',15,'征战各类机器人大赛的尖兵组织。','学术类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','科技,编程,硬件','/uploads/club/Robot.png'),(32,'英语角',2,'提升英语口语，拓展国际视野。','学术类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','语言,学术,外交','/uploads/club/English.png'),(33,'舞蹈社',2,'涵盖街舞、民族舞、拉丁舞等多种舞种。','艺术类组织&社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','艺术,表演,文艺','/uploads/club/Dance.png'),(34,'轮滑社',15,'追逐风的速度，感受滑行的自由。','体育类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','运动,体育,挑战','/uploads/club/Skating.png'),(35,'围棋社',2,'黑白方寸间，尽显智慧博弈。','逸趣类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','棋类,学术,文化','/uploads/club/Go.png'),(36,'天文协会',15,'仰望星空，探索宇宙的奥秘。','学术类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','科技,地理,星空','/uploads/club/Astronomy.png'),(37,'汉服社',2,'弘扬传统服饰文化，展现华夏之美。','艺术类组织&社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','艺术,文化,传统','/uploads/club/Hanfu.png'),(38,'桌游社',2,'逻辑与娱乐的完美结合。','逸趣类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','游戏,社交,逻辑','/uploads/club/BoardGame.png'),(39,'职业发展协会',2,'助力职业规划，提升就业竞争力。','功能性组织',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','管理,职场,服务','/uploads/club/Career.png'),(40,'模型社',15,'比例的世界，极致的匠心。','逸趣类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','艺术,手工,科技','/uploads/club/Model.png'),(41,'排球社',2,'女排精神，在校园传承。','体育类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','运动,体育,团队','/uploads/club/Volleyball.png'),(42,'武术社',2,'强身健体，传承国粹。','体育类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','运动,文化,武术','/uploads/club/Wushu.png'),(43,'红十字会',2,'开展急救培训与献血服务。','公益类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','医疗,公益,志愿服务','/uploads/club/RedCross.png'),(44,'滑板社',15,'街头文化，挑战自我。','体育类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','运动,时尚,潮流','/uploads/club/Skateboard.png'),(45,'播音主持协会',15,'用声音传递力量。','艺术类组织&社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','艺术,文艺,语言','/uploads/club/Broadcast.png'),(46,'定向越野社',2,'智慧与体力的双重考验。','体育类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','运动,户外,逻辑','/uploads/club/Orienteering.png'),(47,'话剧社',15,'演绎人生百态。','艺术类组织&社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','艺术,表演,文学','/uploads/club/Drama.png'),(48,'创业俱乐部',2,'汇聚创业点子，孵化创新梦想。','功能性组织',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','管理,科技,创业','/uploads/club/Entrepreneur.png'),(49,'乒乓球社',2,'国球交流，强身健体。','体育类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','运动,体育,国球','/uploads/club/PingPong.png'),(50,'数学建模社',2,'用数学语言描述世界。','学术类社团',1,'2026-04-18 11:00:00','2026-04-18 11:00:00','学术,科技,竞赛','/uploads/club/MathModel.png'),(51,'白帽子网络安全实验室',15,'实验室专注于网络攻防技术的深度研究与实践，通过CTF竞赛、渗透模拟与漏洞挖掘，培养顶尖白帽子人才。','学术类社团',1,'2026-04-22 16:59:55','2026-04-22 19:22:35','网络安全,CTF,渗透测试,代码审计,编程','/uploads/logo/security_lab.png'),(52,'ACM队',18,'ACM队专注于编程能力与算法思维培养。定期举办集训、模拟赛、算法分享与竞赛指导，助力成员备战各类程序设计大赛，提升代码能力与逻辑思维。热爱编程、喜欢挑战的同学，欢迎加入我们，一起用算法书写热爱！','学术类社团',0,'2026-04-22 21:34:48','2026-04-22 21:37:01','编程、竞赛、学术、算法','/uploads/2026/04/22/67592ce16a86464fbceb0a12aa074ac1.png');
