DROP TABLE IF EXISTS `club_member`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `club_member` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `club_id` bigint NOT NULL COMMENT '社团ID（关联club_info.id）',
  `student_id` bigint NOT NULL COMMENT '学生ID（关联sys_user.id）',
  `intro` text,
  `member_type` tinyint DEFAULT '0' COMMENT '成员类型：0-普通成员，1-核心成员',
  `join_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '加入时间',
  `status` tinyint DEFAULT '1' COMMENT '成员状态：1-正常，0-已退出',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_club_student` (`club_id`,`student_id`) COMMENT '一人一社团只能加入一次',
  KEY `idx_student_id` (`student_id`) COMMENT '学生ID索引',
  KEY `idx_status` (`status`) COMMENT '成员状态索引',
  KEY `idx_stu_club` (`student_id`,`club_id`),
  CONSTRAINT `fk_member_club` FOREIGN KEY (`club_id`) REFERENCES `club_info` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_member_student` FOREIGN KEY (`student_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='社团成员表';
/*!40101 SET character_set_client = @saved_cs_client */;

