DROP TABLE IF EXISTS `news`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `news` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '新闻ID',
  `title` varchar(255) NOT NULL COMMENT '新闻标题',
  `content` longtext COMMENT '新闻内容（富文本HTML）',
  `cover_img` varchar(500) DEFAULT NULL COMMENT '详情页封面图路径',
  `img` varchar(500) DEFAULT NULL COMMENT '列表展示图路径',
  `publisher` varchar(50) DEFAULT '管理员' COMMENT '发布人',
  `publish_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '发布时间',
  `type` int DEFAULT '0' COMMENT '新闻类型：0-新闻 1-公告',
  `sort` int DEFAULT '0' COMMENT '排序权重',
  `status` int DEFAULT '1' COMMENT '状态：1-显示 0-隐藏',
  PRIMARY KEY (`id`),
  KEY `idx_status` (`status`),
  KEY `idx_publish_time` (`publish_time`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='新闻表';
