INSERT INTO `news` VALUES (1,'学校召开2026年关心下一代工作会议','2026年4月8日，学校召开2026年关心下一代工作会议，总结2025年工作，部署2026年重点任务，进一步推动学校关心下一代工作高质量发展。',NULL,NULL,'党委宣传部','2026-04-08 09:00:00',1,1,1),(2,'我校与江西省人民政府签署战略合作协议','2026年4月7日，中国地质大学（北京）与江西省人民政府签署战略合作协议，双方将围绕地质资源、生态环境、人才培养等领域深化合作，服务国家战略和地方发展。',NULL,NULL,'党委宣传部','2026-04-07 10:30:00',1,2,1),(3,'聚焦“教育科技人才”一体发展 高校宣传思想工作创新微论坛在我校举办','2026年4月4日，聚焦“教育科技人才”一体发展高校宣传思想工作创新微论坛在我校举办，来自多所高校的宣传思想工作者齐聚一堂，交流经验、共话发展。',NULL,NULL,'党委宣传部','2026-04-04 14:00:00',1,3,1),(4,'我校召开本科教育教学审核评估整改工作推进会','2026年4月3日，学校召开本科教育教学审核评估整改工作推进会，通报整改进展，部署下一阶段重点工作，确保整改任务落地见效，持续提升本科教育教学质量。',NULL,NULL,'教务处','2026-04-03 09:30:00',1,4,1),(5,'农工党地大支部举办“走进地大”健康专题讲座','2026年4月3日，农工党地大支部举办“走进地大”健康专题讲座，邀请专家为师生开展健康知识科普，提升师生健康素养和自我保健能力。',NULL,NULL,'校工会','2026-04-03 15:00:00',1,5,1),(6,'校领导带队开展清明节前校园安全检查','2026年4月3日，校领导带队开展清明节前校园安全检查，重点排查校园消防、治安、设施等安全隐患，筑牢校园安全防线，保障师生平安过节。',NULL,NULL,'保卫处','2026-04-03 16:00:00',1,6,1),(7,'中国矿业大学校长张吉雄一行来访我校','2026年4月2日，中国矿业大学校长张吉雄一行来访我校，双方就学科建设、人才培养、科研合作等方面进行深入交流，推动两校协同发展。',NULL,NULL,'党委办公室','2026-04-02 10:00:00',1,7,1),(8,'（人民网）赵志丹：加快推进学科专业结构性改革','人民网刊发我校赵志丹教授文章《加快推进学科专业结构性改革》，围绕新时代高等教育学科专业建设，提出改革思路与实践路径，为高校内涵式发展提供参考。',NULL,NULL,'党委宣传部','2026-04-02 11:00:00',1,8,1),(9,'学校党委树立和践行正确政绩观学习教育读书班圆满结业','2026年4月1日，学校党委树立和践行正确政绩观学习教育读书班圆满结业，通过集中学习、研讨交流等形式，深化党员干部思想认识，推动学校事业高质量发展。',NULL,NULL,'党委宣传部','2026-04-01 17:00:00',1,9,1);
/*!40000 ALTER TABLE `news` ENABLE KEYS */;
UNLOCK TABLES;

