--
-- Table structure for table `sys_user`
--

DROP TABLE IF EXISTS `sys_user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_user` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `username` varchar(50) NOT NULL COMMENT '账号（学号/工号/管理员账号）',
  `password` varchar(100) NOT NULL COMMENT '密码（BCrypt加密）',
  `user_type` varchar(20) NOT NULL COMMENT '用户类型：student/leader/admin',
  `name` varchar(20) NOT NULL COMMENT '真实姓名',
  `phone` varchar(11) NOT NULL COMMENT '联系电话',
  `tags` varchar(100) DEFAULT NULL COMMENT '学生兴趣标签（逗号分隔，如：academic,sports）',
  `mbti` varchar(10) DEFAULT NULL COMMENT '学生MBTI性格类型',
  `club_name` varchar(50) DEFAULT NULL COMMENT '社团负责人所属社团',
  `status` tinyint DEFAULT '1' COMMENT '账号状态：1-正常，0-禁用',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `avatar` varchar(500) DEFAULT NULL COMMENT '用户头像',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_username` (`username`) COMMENT '账号唯一索引',
  KEY `idx_user_type` (`user_type`) COMMENT '用户类型索引'
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统用户表';
/*!40101 SET character_set_client = @saved_cs_client */;

